import React, { useState, useEffect, useRef, useMemo } from 'react';

const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    blue: '#38bdf8',
    yellow: '#fbbf24',
    pink: '#f472b6',
    green: '#a3e635',
    orange: '#fb923c',
    red: '#f43f5e',
  },
  font: "'JetBrains Mono', monospace",
};

const VALS = [-1, -0.5, 0, 0.5, 1, 1.5, 2];

const presets = [
  { name: 'Scaling', w1: [[1,0],[0,1]], w2: [[0.5,0],[0,0.5]], x: [1,2] },
  { name: 'Zero Path', w1: [[0,0],[0,0]], w2: [[0,0],[0,0]], x: [1,2] },
  { name: 'Negative', w1: [[-1,0],[0,1]], w2: [[1,0],[0,1]], x: [1,2] },
  { name: 'Cross', w1: [[0,1],[1,0]], w2: [[0.5,0],[0,0.5]], x: [2,3] },
];

function compute(x, w1, w2) {
  const aW1 = [
    w1[0][0]*x[0] + w1[0][1]*x[1],
    w1[1][0]*x[0] + w1[1][1]*x[1]
  ];
  const aR1 = aW1.map(v => Math.max(0, v));
  const aW2 = [
    w2[0][0]*aR1[0] + w2[0][1]*aR1[1],
    w2[1][0]*aR1[0] + w2[1][1]*aR1[1]
  ];
  const aAdd = [aW2[0] + x[0], aW2[1] + x[1]];
  const out = aAdd.map(v => Math.max(0, v));
  return { aW1, aR1, aW2, aAdd, out };
}

function fmt(v) { return v.toFixed(2); }

function MatrixGrid({ mat, onChange, label, color, active }) {
  return (
    <div style={{ textAlign: 'center' }}>
      <div style={{ fontSize: 11, color: active ? color : theme.colors.textMuted, marginBottom: 4, fontWeight: 600, transition: 'color 0.3s' }}>{label}</div>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 3 }}>
        {[0,1].map(r => [0,1].map(c => {
          const val = mat[r][c];
          return (
            <div key={`${r}${c}`}
              onClick={() => {
                const idx = VALS.indexOf(val);
                const next = VALS[(idx + 1) % VALS.length];
                const nm = mat.map(row => [...row]);
                nm[r][c] = next;
                onChange(nm);
              }}
              style={{
                width: 44, height: 32, display: 'flex', alignItems: 'center', justifyContent: 'center',
                background: active ? theme.colors.surfaceAlt : theme.colors.surface,
                border: `1px solid ${active ? color + '55' : theme.colors.border}`,
                borderRadius: 6, cursor: 'pointer', fontSize: 13, fontWeight: 600,
                color: val === 0 ? theme.colors.textMuted : theme.colors.text,
                fontFamily: theme.font, transition: 'all 0.2s',
                userSelect: 'none',
              }}
              onMouseEnter={e => { e.currentTarget.style.borderColor = color; e.currentTarget.style.background = color + '18'; }}
              onMouseLeave={e => { e.currentTarget.style.borderColor = active ? color + '55' : theme.colors.border; e.currentTarget.style.background = active ? theme.colors.surfaceAlt : theme.colors.surface; }}
            >{fmt(val)}</div>
          );
        }))}
      </div>
    </div>
  );
}

function VecDisplay({ vals, color, label, active, showClip }) {
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 6, opacity: active ? 1 : 0.3, transition: 'opacity 0.4s' }}>
      {label && <span style={{ fontSize: 10, color: theme.colors.textMuted, width: 28, textAlign: 'right' }}>{label}</span>}
      <div style={{ display: 'flex', gap: 4 }}>
        {vals.map((v, i) => (
          <div key={i} style={{
            background: color + '18', border: `1px solid ${color}44`,
            borderRadius: 6, padding: '3px 8px', fontSize: 13, fontWeight: 700,
            color: showClip && v <= 0 && vals !== undefined ? theme.colors.red : color,
            fontFamily: theme.font, minWidth: 48, textAlign: 'center',
            transition: 'all 0.3s',
          }}>{fmt(v)}</div>
        ))}
      </div>
    </div>
  );
}

export default function App() {
  const [x, setX] = useState([1, 2]);
  const [w1, setW1] = useState([[1,0],[0,1]]);
  const [w2, setW2] = useState([[0.5,0],[0,0.5]]);
  const [step, setStep] = useState(0);
  const [playing, setPlaying] = useState(false);
  const timerRef = useRef(null);

  const MAX_STEP = 5;
  const res = useMemo(() => compute(x, w1, w2), [x, w1, w2]);

  useEffect(() => {
    if (playing) {
      timerRef.current = setInterval(() => {
        setStep(s => {
          if (s >= MAX_STEP) { setPlaying(false); return MAX_STEP; }
          return s + 1;
        });
      }, 1200);
    }
    return () => clearInterval(timerRef.current);
  }, [playing]);

  const reset = () => { setStep(0); setPlaying(false); };
  const play = () => { if (step >= MAX_STEP) setStep(0); setPlaying(true); };

  const applyPreset = (p) => {
    setW1(p.w1.map(r => [...r]));
    setW2(p.w2.map(r => [...r]));
    setX([...p.x]);
    setStep(0);
    setPlaying(false);
  };

  const stepLabels = ['Input x', 'W1 * x', 'ReLU', 'W2 * y', 'F(x) + x', 'Final ReLU'];
  const stepColors = [theme.colors.blue, theme.colors.yellow, theme.colors.yellow, theme.colors.orange, theme.colors.pink, theme.colors.green];

  const stepVals = [
    x,
    res.aW1,
    res.aR1,
    res.aW2,
    res.aAdd,
    res.out,
  ];

  const fxIsZero = res.aW2[0] === 0 && res.aW2[1] === 0;
  const reluClipped = res.aW1.some(v => v < 0);
  const shortcutSaved = res.aAdd.some((v, i) => v !== res.aW2[i]) && step >= 4;
  const finalClipped = res.aAdd.some(v => v < 0);

  const getInsight = () => {
    if (step === 0) return 'This is the input vector x. It flows through both the main path (W1, ReLU, W2) and the shortcut connection.';
    if (step === 1) return `W1 multiplied by x: [${fmt(w1[0][0])}*${fmt(x[0])}+${fmt(w1[0][1])}*${fmt(x[1])}, ${fmt(w1[1][0])}*${fmt(x[0])}+${fmt(w1[1][1])}*${fmt(x[1])}] = [${fmt(res.aW1[0])}, ${fmt(res.aW1[1])}]`;
    if (step === 2) return reluClipped ? `ReLU clips negative values to 0! ${res.aW1.filter(v=>v<0).map(v=>fmt(v)).join(', ')} became 0.` : 'ReLU: all values are non-negative, so nothing changes here.';
    if (step === 3) return `W2 transforms the result. F(x) = [${fmt(res.aW2[0])}, ${fmt(res.aW2[1])}]. This is the learned residual.`;
    if (step === 4) {
      if (fxIsZero) return 'F(x) = 0, but the shortcut preserves x! The block learns an identity mapping. This is why ResNets train deep.';
      return `Shortcut adds x back: [${fmt(res.aW2[0])}+${fmt(x[0])}, ${fmt(res.aW2[1])}+${fmt(x[1])}]. The network learns the residual F(x), not the full transform.`;
    }
    if (step === 5) return finalClipped ? `Final ReLU clips negatives. Output: [${fmt(res.out[0])}, ${fmt(res.out[1])}]` : `All values positive, final ReLU passes through. Output: [${fmt(res.out[0])}, ${fmt(res.out[1])}]`;
    return '';
  };

  // SVG Flow Diagram
  const svgW = 540, svgH = 310;
  const mainX = 150;
  const shortX = 420;
  const nodeW = 180, nodeH = 34;
  const yPositions = [18, 68, 118, 168, 228, 278];

  const renderArrow = (x1, y1, x2, y2, active, color) => (
    <line x1={x1} y1={y1} x2={x2} y2={y2}
      stroke={active ? color : theme.colors.border}
      strokeWidth={active ? 2 : 1}
      strokeDasharray={active ? 'none' : '4,3'}
      markerEnd="url(#arrowhead)"
      style={{ transition: 'all 0.4s' }}
    />
  );

  const renderNode = (idx) => {
    const isActive = step >= idx;
    const isCurrent = step === idx;
    const color = stepColors[idx];
    const yp = yPositions[idx];
    const vals = stepVals[idx];
    const showClip = (idx === 2 && res.aW1.some(v => v < 0)) || (idx === 5 && res.aAdd.some(v => v < 0));

    return (
      <g key={idx}>
        <rect
          x={mainX - nodeW/2} y={yp} width={nodeW} height={nodeH} rx={8}
          fill={isCurrent ? color + '15' : theme.colors.surface}
          stroke={isCurrent ? color : isActive ? color + '44' : theme.colors.border}
          strokeWidth={isCurrent ? 2 : 1}
          style={{ transition: 'all 0.4s' }}
        />
        <text x={mainX - nodeW/2 + 10} y={yp + 14} fontSize={9} fill={isActive ? theme.colors.textSecondary : theme.colors.textMuted}
          fontFamily={theme.font} style={{ transition: 'fill 0.4s' }}>
          {stepLabels[idx]}
        </text>
        {isActive && (
          <>
            <text x={mainX - nodeW/2 + 10} y={yp + 27} fontSize={13} fontWeight={700}
              fill={showClip ? theme.colors.red : color} fontFamily={theme.font}
              style={{ transition: 'fill 0.3s' }}>
              [{vals.map(v => fmt(v)).join(', ')}]
            </text>
          </>
        )}
      </g>
    );
  };

  return (
    <div style={{
      maxWidth: 600, margin: '0 auto', padding: '12px 16px',
      background: theme.colors.background, fontFamily: theme.font,
      color: theme.colors.text, minHeight: '100vh', boxSizing: 'border-box',
    }}>
      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 10 }}>
        <div>
          <div style={{ fontSize: 17, fontWeight: 700 }}>Residual Block</div>
          <div style={{ fontSize: 11, color: theme.colors.textMuted }}>Click weight cells to change values</div>
        </div>
        <div style={{ display: 'flex', gap: 6 }}>
          <button onClick={playing ? () => setPlaying(false) : play} style={{
            background: theme.colors.primary, color: '#fff', border: 'none',
            borderRadius: 8, padding: '6px 14px', fontSize: 12, fontWeight: 600,
            cursor: 'pointer', fontFamily: theme.font,
          }}>{playing ? 'Pause' : step >= MAX_STEP ? 'Replay' : 'Play'}</button>
          <button onClick={reset} style={{
            background: theme.colors.surface, color: theme.colors.textSecondary,
            border: `1px solid ${theme.colors.border}`, borderRadius: 8,
            padding: '6px 10px', fontSize: 12, cursor: 'pointer', fontFamily: theme.font,
          }}>Reset</button>
        </div>
      </div>

      {/* Step indicator */}
      <div style={{ display: 'flex', gap: 3, marginBottom: 10 }}>
        {stepLabels.map((s, i) => (
          <div key={i} onClick={() => { setStep(i); setPlaying(false); }} style={{
            flex: 1, height: 4, borderRadius: 2, cursor: 'pointer',
            background: step >= i ? stepColors[i] : theme.colors.border,
            opacity: step >= i ? 1 : 0.4, transition: 'all 0.3s',
          }} />
        ))}
      </div>

      {/* Main SVG Flow */}
      <div style={{ background: theme.colors.surface, borderRadius: 12, padding: '8px 8px 4px', marginBottom: 10 }}>
        <svg width={svgW} height={svgH} viewBox={`0 0 ${svgW} ${svgH}`} style={{ display: 'block', margin: '0 auto', maxWidth: '100%' }}>
          <defs>
            <marker id="arrowhead" markerWidth="8" markerHeight="6" refX="8" refY="3" orient="auto">
              <polygon points="0 0, 8 3, 0 6" fill={theme.colors.textMuted} />
            </marker>
            <marker id="arrowActive" markerWidth="8" markerHeight="6" refX="8" refY="3" orient="auto">
              <polygon points="0 0, 8 3, 0 6" fill={theme.colors.pink} />
            </marker>
          </defs>

          {/* Main path arrows */}
          {[0,1,2,3,4].map(i => (
            <line key={`arr${i}`}
              x1={mainX} y1={yPositions[i] + nodeH + 2}
              x2={mainX} y2={yPositions[i+1] - 2}
              stroke={step > i ? stepColors[i+1] + '88' : theme.colors.border}
              strokeWidth={step > i ? 1.5 : 1}
              strokeDasharray={step > i ? 'none' : '3,3'}
              markerEnd="url(#arrowhead)"
              style={{ transition: 'all 0.4s' }}
            />
          ))}

          {/* Shortcut connection */}
          <path
            d={`M ${mainX + nodeW/2 + 5} ${yPositions[0] + nodeH/2} 
                L ${shortX} ${yPositions[0] + nodeH/2} 
                L ${shortX} ${yPositions[4] + nodeH/2} 
                L ${mainX + nodeW/2 + 5} ${yPositions[4] + nodeH/2}`}
            fill="none"
            stroke={step >= 4 ? theme.colors.pink : theme.colors.border}
            strokeWidth={step >= 4 ? 2.5 : 1}
            strokeDasharray={step >= 4 ? 'none' : '6,4'}
            markerEnd={step >= 4 ? 'url(#arrowActive)' : 'url(#arrowhead)'}
            style={{ transition: 'all 0.5s' }}
          />

          {/* Shortcut label */}
          <text x={shortX + 8} y={yPositions[2] + 10} fontSize={10}
            fill={step >= 4 ? theme.colors.pink : theme.colors.textMuted}
            fontFamily={theme.font} style={{ transition: 'fill 0.4s' }}>
            shortcut
          </text>
          <text x={shortX + 8} y={yPositions[2] + 24} fontSize={11} fontWeight={700}
            fill={step >= 4 ? theme.colors.pink : theme.colors.textMuted}
            fontFamily={theme.font} style={{ transition: 'fill 0.4s' }}>
            x = [{x.map(v=>fmt(v)).join(', ')}]
          </text>

          {/* Operation labels on arrows */}
          {step >= 1 && <text x={mainX + 20} y={yPositions[0] + nodeH + 16} fontSize={9} fill={theme.colors.textMuted} fontFamily={theme.font}>W1 * x</text>}
          {step >= 2 && <text x={mainX + 20} y={yPositions[1] + nodeH + 16} fontSize={9} fill={theme.colors.textMuted} fontFamily={theme.font}>max(0, y)</text>}
          {step >= 3 && <text x={mainX + 20} y={yPositions[2] + nodeH + 16} fontSize={9} fill={theme.colors.textMuted} fontFamily={theme.font}>W2 * y</text>}
          {step >= 4 && <text x={mainX + 20} y={yPositions[3] + nodeH + 16} fontSize={9} fill={theme.colors.pink} fontFamily={theme.font} fontWeight={600}>+ shortcut x</text>}
          {step >= 5 && <text x={mainX + 20} y={yPositions[4] + nodeH + 16} fontSize={9} fill={theme.colors.textMuted} fontFamily={theme.font}>max(0, y)</text>}

          {/* Render nodes */}
          {yPositions.map((_, i) => renderNode(i))}

          {/* F(x) label */}
          {step >= 3 && (
            <text x={mainX - nodeW/2 - 8} y={yPositions[3] + nodeH/2 + 4} fontSize={10}
              fill={theme.colors.orange} fontFamily={theme.font} textAnchor="end" fontWeight={600}>F(x)</text>
          )}
          {step >= 4 && (
            <text x={mainX - nodeW/2 - 8} y={yPositions[4] + nodeH/2 + 4} fontSize={10}
              fill={theme.colors.pink} fontFamily={theme.font} textAnchor="end" fontWeight={600}>F(x)+x</text>
          )}
        </svg>
      </div>

      {/* Weight Matrices + Presets */}
      <div style={{ display: 'flex', alignItems: 'flex-start', gap: 16, marginBottom: 10 }}>
        <MatrixGrid mat={w1} onChange={(m) => { setW1(m); if(step>0) setStep(0); setPlaying(false); }} label="W1" color={theme.colors.yellow} active={step >= 1} />
        <MatrixGrid mat={w2} onChange={(m) => { setW2(m); if(step>0) setStep(0); setPlaying(false); }} label="W2" color={theme.colors.orange} active={step >= 3} />

        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 10, color: theme.colors.textMuted, marginBottom: 4 }}>Input x</div>
          <div style={{ display: 'flex', gap: 4, marginBottom: 8 }}>
            {x.map((v, i) => (
              <div key={i} onClick={() => {
                const idx = VALS.indexOf(v);
                const nv = [...x];
                nv[i] = VALS[(idx + 1) % VALS.length];
                setX(nv);
                if(step>0){ setStep(0); setPlaying(false); }
              }} style={{
                width: 44, height: 32, display: 'flex', alignItems: 'center', justifyContent: 'center',
                background: theme.colors.surfaceAlt, border: `1px solid ${theme.colors.blue}44`,
                borderRadius: 6, cursor: 'pointer', fontSize: 13, fontWeight: 600,
                color: theme.colors.blue, fontFamily: theme.font,
              }}>{fmt(v)}</div>
            ))}
          </div>
          <div style={{ fontSize: 10, color: theme.colors.textMuted, marginBottom: 4 }}>Presets</div>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: 4 }}>
            {presets.map((p, i) => (
              <button key={i} onClick={() => applyPreset(p)} style={{
                background: theme.colors.surfaceAlt, border: `1px solid ${theme.colors.border}`,
                borderRadius: 6, padding: '4px 8px', fontSize: 10, color: theme.colors.textSecondary,
                cursor: 'pointer', fontFamily: theme.font,
              }}>{p.name}</button>
            ))}
          </div>
        </div>
      </div>

      {/* Insight */}
      <div style={{
        background: theme.colors.surface, borderRadius: 8, padding: '10px 14px',
        fontSize: 11, color: theme.colors.textSecondary, lineHeight: 1.6,
        borderLeft: `3px solid ${stepColors[step]}`, transition: 'border-color 0.3s',
      }}>
        <span style={{ color: stepColors[step], fontWeight: 700 }}>
          {step === 0 ? 'Input: ' : step <= 3 ? 'Transform: ' : step === 4 ? 'Shortcut: ' : 'Output: '}
        </span>
        {getInsight()}
      </div>
    </div>
  );
}
